#!/bin/bash
set -o errexit
set -o nounset
set -o pipefail

# shellcheck disable=SC2016
HEADER='#:schema https://starship.rs/config-schema.json
# This file is @generated by `mise run gen:starship`.
# DO NOT EDIT!'

config_dir="$MISE_CONFIG_ROOT/modules/shell/starship/dot_config"
starship_config="$config_dir/starship.toml"
{
  echo "$HEADER"
  uv run "$MISE_CONFIG_ROOT/scripts/tools/toml-merge.py" \
    <(starship preset bracketed-segments) \
    <(starship preset nerd-font-symbols) \
    "$MISE_CONFIG_ROOT/assets/starship/custom.toml"
} > "$starship_config"

starship_remote_config="$config_dir/starship.remote.toml"
{
  echo "$HEADER"
  uv run "$MISE_CONFIG_ROOT/scripts/tools/toml-merge.py" \
    <(starship preset bracketed-segments) \
    <(starship preset nerd-font-symbols) \
    "$MISE_CONFIG_ROOT/assets/starship/custom.toml" \
    "$MISE_CONFIG_ROOT/assets/starship/remote.toml"
} > "$starship_remote_config"

starship_configs=(
  "$starship_config"
  "$starship_remote_config"
)

tombi format "${starship_configs[@]}"
tombi lint "${starship_configs[@]}"
